389	export type SelectionSetRule = {
390	  field: 'category' | 'level' | 'typeName';
391	  operator: 'equals' | 'contains';
392	  value: string;
393	  /**
394	   * FED-02: which models the rule resolves against. `'host'` (default) only
395	   * matches host elements; `'all_links'` walks every `link_model` element and
396	   * matches inside source models too; `{ specificLinkId }` restricts to one
397	   * link. Linked element AABBs are transformed by the link's positionMm +
398	   * rotationDeg before clash-checking.
399	   */
400	  linkScope?: 'host' | 'all_links' | { specificLinkId: string };
401	};
