403	/**
404	 * FED-03: structured monitor-source pointer used by Copy/Monitor.
405	 *
406	 * `linkId` (when set) names a `link_model` element in the host whose source
407	 * model contains the monitored element; intra-host monitors omit it.
408	 * `elementId` is the **source-side** id (not the `<linkId>::<sourceElemId>`
409	 * prefixed form). `sourceRevisionAtCopy` is the source model's revision
410	 * counter at the moment of the copy; the BumpMonitoredRevisions command
411	 * compares it against the latest revision and flags drift.
412	 *
413	 * `drifted` and `driftedFields` are computed by BumpMonitoredRevisions; they
414	 * persist on the host element so the constraint evaluator can emit a
415	 * `monitored_source_drift` advisory without needing live source access.
416	 */
417	export type MonitorSource = {
418	  linkId?: string | null;
419	  elementId: string;
420	  sourceRevisionAtCopy: number;
421	  drifted?: boolean;
422	  driftedFields?: string[];
423	};
