425	export type ClashResult = {
426	  elementIdA: string;
427	  elementIdB: string;
428	  distanceMm: number;
429	  /**
430	   * FED-02: provenance chain for cross-link clashes. Empty array for host
431	   * elements; otherwise a single-element array `[linkId]` identifying the
432	   * `link_model` row whose source contains the element. (Multi-hop transitive
433	   * links are deferred — the FED-01 expander is single-hop only.)
434	   */
435	  linkChainA?: string[];
436	  linkChainB?: string[];
437	};
