643	       * KRN-16 — wall recess / setback zones along the wall's alongT axis.
644	       *
645	       * When set, the wall plane steps back by `setbackMm` (toward its
646	       * interior normal) over the alongT range `[alongTStart, alongTEnd]`.
647	       * Hosted openings whose alongT falls inside the zone are repositioned
648	       * onto the recessed surface. Use cases: loggias, deep entry porches,
649	       * bay windows.
650	       */
651	      recessZones?: {
652	        alongTStart: number;
653	        alongTEnd: number;
654	        setbackMm: number;
655	        sillHeightMm?: number;
656	        headHeightMm?: number;
657	        floorContinues?: boolean;
658	      }[];
659	      /** IFC-04: optional OmniClass / Uniclass / NSCC code emitted as
