      animationRange?: { startIso: string; endIso: string; intervalMinutes: number } | null;
      daylightSavingStrategy: 'auto' | 'on' | 'off';
    }
  | View
  | ToposolidElem
  | AssetLibraryEntryElem
  | PlacedAssetElem;

