1	/**
2	 * EDT-01 — door grip provider.
3	 *
4	 * A door rides its host wall at parameter `alongT ∈ [0, 1]`. The grip
5	 * sits at the door's current point on the wall; dragging projects the
6	 * cursor delta onto the wall's direction and converts that to a delta
7	 * in `alongT`. The numeric override interprets the typed value as a
8	 * distance (mm) from the wall's start.
9	 *
10	 * Both the drag-commit and the numeric-override emit
11	 * `updateElementProperty` on `alongT` so the engine path stays narrow
12	 * (no new command type required).
13	 */
14	import type { Element, XY } from '@bim-ai/core';
15	
16	import type {
17	  ElementGripProvider,
18	  GripCommand,
19	  GripDescriptor,
20	  PlanContext,
21	} from '../gripProtocol';
22	
23	export type Door = Extract<Element, { kind: 'door' }>;
24	export type Wall = Extract<Element, { kind: 'wall' }>;
25	
26	function findWall(door: Door, ctx: PlanContext): Wall | null {
27	  const host = ctx.elementsById?.[door.wallId];
28	  return host && host.kind === 'wall' ? host : null;
29	}
30	
31	function pointOnWall(wall: Wall, t: number): XY {
32	  const clampedT = Math.min(1, Math.max(0, t));
33	  return {
34	    xMm: wall.start.xMm + (wall.end.xMm - wall.start.xMm) * clampedT,
35	    yMm: wall.start.yMm + (wall.end.yMm - wall.start.yMm) * clampedT,
36	  };
37	}
38	
39	function wallLengthMm(wall: Wall): number {
40	  return Math.hypot(wall.end.xMm - wall.start.xMm, wall.end.yMm - wall.start.yMm);
41	}
42	
43	function deltaTFromDelta(wall: Wall, delta: XY): number {
44	  const len = wallLengthMm(wall);
45	  if (len === 0) return 0;
46	  const ux = (wall.end.xMm - wall.start.xMm) / len;
47	  const uy = (wall.end.yMm - wall.start.yMm) / len;
48	  return (delta.xMm * ux + delta.yMm * uy) / len;
49	}
50	
51	function clamp01(v: number): number {
52	  if (!Number.isFinite(v)) return 0;
53	  return Math.min(1, Math.max(0, v));
54	}
55	
56	export const doorGripProvider: ElementGripProvider<Door> = {
57	  grips(door: Door, context: PlanContext): GripDescriptor[] {
58	    const wall = findWall(door, context);
59	    if (!wall) return [];
60	    const len = wallLengthMm(wall);
61	    const slideGrip: GripDescriptor = {
62	      id: `${door.id}:alongT`,
63	      positionMm: pointOnWall(wall, door.alongT),
64	      shape: 'circle',
65	      axis: 'free',
66	      hint: 'Drag to slide along host wall',
